const items = $input.all();
const bobJobs = [];
const wowJobs = [];

items.forEach((item) => {
  const job = {
    jobId: item.json.jobId,
    jobTitle: item.json.jobTitle,
    companyName: item.json.companyName,
    location: item.json.location,
    sector: item.json.sector,
    experienceLevel: item.json.experienceLevel,
    workType: item.json.workType,
    jobDescription: item.json.jobDescription,
  };

  if (item.json.analysisGroup === "BOB") {
    bobJobs.push(job);
  } else if (item.json.analysisGroup === "WOW") {
    wowJobs.push(job);
  }
});

return [
  { json: { bobJobs, wowJobs }, pairedItem: items.map((_, index) => index) },
];

return items.map((item, index) => {
  let raw = item.json.text;

  if (!raw) {
    throw new Error(`Item ${index}: No text field found from LLM output.`);
  }

  raw = String(raw).trim();

  // Remove markdown fences if present
  raw = raw
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  // If the model added text around the JSON, keep only the JSON object
  const firstBrace = raw.indexOf("{");
  const lastBrace = raw.lastIndexOf("}");

  if (firstBrace === -1 || lastBrace === -1) {
    throw new Error(`Item ${index}: Could not find JSON object in LLM output.`);
  }

  raw = raw.slice(firstBrace, lastBrace + 1);

  // Repair common LLM JSON mistakes:
  // 1. Invalid escaped apostrophes: don\'t -> don't
  // 2. Invalid escaped underscores/slashes in normal text
  raw = raw
    .replace(/\\'/g, "'")
    .replace(/\\_/g, "_");

  let parsed;

  try {
    parsed = JSON.parse(raw);
  } catch (error) {
    throw new Error(
      `Item ${index}: JSON parse failed. ${error.message}\n\nRaw output:\n${raw}`
    );
  }

  return {
    json: {
      ...item.json,
      ...parsed,
      classificationJson: raw,
      classifiedAt: new Date().toISOString(),
      modelUsed: "openai/gpt-oss-120b:free"
    }
  };
});

function extractRelevantDescription(text) {
  if (!text) return "";

  const raw = String(text)
    .replace(/\\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  const lines = raw.split("\n").map(l => l.trim()).filter(Boolean);

  const includeMarkers = [
    "about the role",
    "the role",
    "what you'll do",
    "what you’ll do",
    "what you will do",
    "responsibilities",
    "key responsibilities",
    "requirements",
    "qualifications",
    "what you bring",
    "what you'll bring",
    "what you’ll bring",
    "must-have",
    "must haves",
    "nice-to-have",
    "nice to have",
    "skills",
    "experience",
    "what success looks like",
    "problems you'll solve",
    "problems you’ll solve",
    "mission"
  ];

  const stopMarkers = [
    "benefits",
    "perks",
    "what we offer",
    "compensation",
    "salary",
    "equal opportunity",
    "privacy",
    "our values",
    "who we are",
    "about us",
    "company description",
    "show more",
    "show less"
  ];

  const lowerLines = lines.map(l => l.toLowerCase());

  // Find the first role-relevant section marker.
  let startIndex = lowerLines.findIndex(line =>
    includeMarkers.some(marker => line.includes(marker))
  );

  // If no marker is found, start after the first ~20% of the text to skip company boilerplate.
  if (startIndex === -1) {
    startIndex = Math.min(Math.floor(lines.length * 0.2), 20);
  }

  let selected = [];

  for (let i = startIndex; i < lines.length; i++) {
    const lower = lowerLines[i];

    // Stop only after we have captured enough useful content.
    if (
      selected.length > 20 &&
      stopMarkers.some(marker => lower.includes(marker))
    ) {
      break;
    }

    selected.push(lines[i]);
  }

  let output = selected.join("\n");

  // Hard cap to keep the market-intel prompt manageable.
  // 2500 chars/job * 74 jobs = ~185k chars before JSON overhead.
  // You may need to lower this to 1500–2000 if the model still errors.
  return output.slice(0, 2200);
}

const jobs = items.map(item => ({
  jobTitle: item.json.jobTitle,
  companyName: item.json.companyName,
  location: item.json.location,
  yearsOfExperience: item.json.yearsOfExperience || "",
  marketFitBucket: item.json.marketFitBucket,
  classificationReason: item.json.classificationReason,
  trimmedJobDescription: extractRelevantDescription(item.json.jobDescription)
}));

return [
  {
    json: {
      relevantJobCount: jobs.length,
      jobs
    }
  }
];

